import React, { useState } from 'react';
import { ScrollView, View, Pressable } from 'react-native';
import {
  Text,
  Box,
  SeparatorHorizontal,
  CardVehicleTags,
  Header,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  voucherListLoaded,
  voucherListEmpty,
  voucherListFiltered,
} from '../services/sdui/mocks';

registerAllAdapters();

type ViewState = 'list' | 'empty' | 'filtered';

const SCREENS: Record<ViewState, SDUIScreen> = {
  list: voucherListLoaded,
  empty: voucherListEmpty,
  filtered: voucherListFiltered,
};

function ViewToggle({
  selected,
  onSelect,
}: {
  selected: ViewState;
  onSelect: (v: ViewState) => void;
}) {
  const labels: Record<ViewState, string> = {
    list: 'List (6)',
    empty: 'Empty',
    filtered: 'Filtered',
  };

  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
      {(['list', 'empty', 'filtered'] as const).map(v => (
        <Pressable
          key={v}
          onPress={() => onSelect(v)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {labels[v]}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

function VoucherListDemo() {
  const [view, setView] = useState<ViewState>('list');
  const screen = useSDUIJsonEditor(SCREENS[view]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI: Meus Vouchers
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Renders the voucher list from JSON via SDUI engine. Cards use context
          interpolation — edit the JSON to change data dynamically.
        </Text>

        <ViewToggle selected={view} onSelect={setView} />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

const REAL_SCREEN_ORDERS = (voucherListLoaded.context.orders as Record<string, string>[]).map(o => ({
  icon: String(o.icon),
  desc: String(o.description),
  pts: String(o.points),
  date: String(o.date),
  status: String(o.status),
  tag: String(o.tag),
}));

function RealScreenPreview() {
  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Meus pedidos"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        iconRight="icon-filter-settings"
        onPressRight={() => {}}
      />
      {REAL_SCREEN_ORDERS.map((item, idx) => (
        <Box key={idx} ml="middle" mr="middle" mt="smaller">
          <CardVehicleTags
            vehicleName={item.desc}
            icon={item.icon as any}
            title="Valor em pontos"
            titleDescription={item.pts}
            date="Data do resgate"
            dateNumber={item.date}
            statusTitle="Status do pedido"
            status={item.status}
