import { chromium } from 'playwright';

const STORYBOOK = 'http://localhost:6006';
const DIR = '.storybook/screenshots';

async function run() {
  const browser = await chromium.launch({ headless: true });
  const ctx = await browser.newContext({ viewport: { width: 1400, height: 900 } });
  const page = await ctx.newPage();

  // Screenshot 1: Interactive Dashboard - click first row to expand it
  const interactiveUrl = `${STORYBOOK}/iframe.html?id=sdui-comparison-dashboard--interactive&viewMode=story`;
  await page.goto(interactiveUrl, { waitUntil: 'networkidle' });
  await page.waitForTimeout(2000);

  // Click first row to expand "Voucher Form"
  const firstRow = page.getByText('Voucher Form').first();
  if (await firstRow.isVisible()) {
    await firstRow.click();
    await page.waitForTimeout(1500);
  }
  await page.screenshot({ path: `${DIR}/comparison-dashboard-interactive.png`, fullPage: true });
  console.log('✓ comparison-dashboard-interactive.png');

  // Screenshot 2: All Expanded Dashboard
  const allExpandedUrl = `${STORYBOOK}/iframe.html?id=sdui-comparison-dashboard--all-expanded&viewMode=story`;
  await page.goto(allExpandedUrl, { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: `${DIR}/comparison-dashboard-all-expanded.png`, fullPage: true });
  console.log('✓ comparison-dashboard-all-expanded.png');

  await browser.close();
  console.log('Done!');
}

run().catch(e => { console.error(e); process.exit(1); });

